// LIST FILES NEWER THAN .last_polled
// Compares mtime of each .json against stored timestamp.
// Returns array of {filePath, fileName} for downstream processing.

const fs = require('fs');
const path = require('path');

const HUB_DIR = '/share/CE_CACHEDEV1_DATA/Automations/apex/hub';
const LAST_POLLED_FILE = path.join(HUB_DIR, '.last_polled');
const SYSTEM_FILES = new Set(['.heartbeat', '.foreman_pid', '.last_polled']);

// Read last polled timestamp (ms)
let lastPolled = 0;
try {
  const raw = fs.readFileSync(LAST_POLLED_FILE, 'utf8').trim();
  lastPolled = parseInt(raw) || 0;
} catch (e) { /* first run */ }

const now = Date.now();

// List hub/ for new .json files
const newFiles = [];
try {
  const entries = fs.readdirSync(HUB_DIR);
  for (const entry of entries) {
    if (!entry.endsWith('.json')) continue;
    if (SYSTEM_FILES.has(entry) || entry.startsWith('.')) continue;
    const fullPath = path.join(HUB_DIR, entry);
    try {
      const stat = fs.statSync(fullPath);
      if (stat.mtimeMs > lastPolled) {
        newFiles.push({ filePath: fullPath, fileName: entry, _source: 'poll' });
      }
    } catch (e) { /* file may have been processed and removed */ }
  }
} catch (e) {
  return [{ json: { error: e.message } }];
}

// Update .last_polled timestamp
fs.writeFileSync(LAST_POLLED_FILE, now.toString());

if (newFiles.length === 0) return [];

return newFiles.map(f => ({ json: f }));

// NORMALIZE: Accepts output from either FSW trigger or Poll path.
// FSW output: $json.path (full file path), $json.type (event type)
// Poll output: $json.filePath, $json.fileName
// Returns: { filePath, fileName } or [] to halt.

const path = require('path');

const filePath = $json.filePath || $json.path || '';
if (!filePath) return [];

const fileName = path.basename(filePath);

// Skip system/hidden files and .tmp directory contents
const SKIP = new Set(['.heartbeat', '.foreman_pid', '.last_polled']);
if (SKIP.has(fileName)) return [];
if (fileName.startsWith('.')) return [];
if (!fileName.endsWith('.json')) return [];
if (filePath.includes('/.tmp/') || filePath.includes('/.tmp/')) return [];

// Skip delete events from FSW
if ($json.type === 'unlink' || $json.type === 'unlinkDir') return [];

return [{ json: { filePath, fileName, _source: $json._source || 'fsw' } }];

// READ AND VALIDATE TICKET
// Reads file at filePath, parses JSON, validates meta.receiver exists.
// Returns full ticket data + _filePath and _receiver fields for routing.
// Logs malformed tickets to relay.log and halts (returns []).

const fs = require('fs');
const path = require('path');

const LOG_FILE = '/share/CE_CACHEDEV1_DATA/Automations/apex/logs/relay.log';
const filePath = $json.filePath;

function appendLog(entry) {
  try { fs.appendFileSync(LOG_FILE, JSON.stringify(entry) + '\n'); } catch(e) {}
}

if (!filePath) {
  appendLog({ timestamp: new Date().toISOString(), level: 'ERROR', message: 'No filePath in normalize output' });
  return [];
}

// Read file
let rawContent;
try {
  rawContent = fs.readFileSync(filePath, 'utf8');
} catch (e) {
  appendLog({ timestamp: new Date().toISOString(), level: 'ERROR', message: `Cannot read file: ${e.message}`, filePath });
  return [];
}

// Parse JSON
let ticket;
try {
  ticket = JSON.parse(rawContent);
} catch (e) {
  appendLog({ timestamp: new Date().toISOString(), level: 'ERROR', message: `MALFORMED_TICKET: JSON parse error: ${e.message}`, filePath });
  return [];
}

// Validate meta.receiver â€” CONSTRAINT: n8n reads ONLY this field for routing
const receiver = ticket?.meta?.receiver;
if (!receiver || typeof receiver !== 'string') {
  appendLog({ timestamp: new Date().toISOString(), level: 'ERROR', message: 'MALFORMED_TICKET: missing meta.receiver', filePath });
  return [];
}

return [{ json: { ...ticket, _filePath: filePath, _receiver: receiver.toLowerCase() } }];

// NOTIFY ORIGINATOR â€” severity-based routing
// FATAL/ERROR: pass to Telegram alert node
// WARN/INFO: log only, return []

const fs = require('fs');

const LOG_FILE = '/share/CE_CACHEDEV1_DATA/Automations/apex/logs/relay.log';
const severity = $json?.meta?.severity || 'INFO';
const jobId = $json?.meta?.parent_job_id || $json?.meta?.job_id || 'unknown';
const message = $json?.failure?.message || JSON.stringify($json).slice(0, 200);
const stage = $json?.failure?.stage || 'UNKNOWN';

const logEntry = JSON.stringify({
  timestamp: new Date().toISOString(),
  job_id: jobId,
  receiver: 'originator',
  action: `DIAGNOSTIC/${stage}`,
  severity,
  message
});
fs.appendFileSync(LOG_FILE, logEntry + '\n');

if (severity === 'FATAL' || severity === 'ERROR') {
  return [{ json: {
    ...$json,
    _notifyText: `[Apex ${severity}] Job ${jobId}\nStage: ${stage}\n${message}`
  }}];
}

// WARN or INFO: log only
return [];

// LOG UNKNOWN RECEIVER â€” halt gracefully
const fs = require('fs');
const LOG_FILE = '/share/CE_CACHEDEV1_DATA/Automations/apex/logs/relay.log';
const receiver = $json?._receiver || 'unknown';
const filePath = $json?._filePath || '';
const jobId = $json?.meta?.job_id || 'unknown';

const entry = JSON.stringify({
  timestamp: new Date().toISOString(),
  level: 'WARN',
  message: `Unknown receiver: '${receiver}' â€” ticket not routed`,
  job_id: jobId,
  filePath
});
fs.appendFileSync(LOG_FILE, entry + '\n');
console.warn(`[Blind Postman] Unknown receiver: '${receiver}' for job ${jobId}`);
return [];

// RELAY LOG â€” append final outcome to relay.log
const fs = require('fs');
const LOG_FILE = '/share/CE_CACHEDEV1_DATA/Automations/apex/logs/relay.log';

const jobId = $json?.meta?.job_id || $json?.meta?.parent_job_id || 'unknown';
const receiver = $json?._receiver || $json?.meta?.receiver || 'unknown';
const severity = $json?.meta?.severity || 'INFO';
const action = $json?.sop?.action || $json?.failure?.stage || 'dispatch';

const entry = JSON.stringify({
  timestamp: new Date().toISOString(),
  job_id: jobId,
  receiver,
  action,
  severity
});
fs.appendFileSync(LOG_FILE, entry + '\n');

return [{ json: { logged: true, job_id: jobId } }];
